import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ServerStatusData {
  server: string;
  status: {
    uptimePercentage: number;
    averageResponseTime: number;
    currentErrors: number;
  };
  errorRateTrend: { hour: string; errors: number }[];
  responseTimeTrend: number[];
}

export default function Widget() {
  const data = response.data as ServerStatusData;
  const { server, status, errorRateTrend, responseTimeTrend } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#0D1117' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#58A6FF', fontWeight: 600 }}>
              {server} Status
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
              <Chip label={`Uptime: ${status.uptimePercentage}%`} sx={{ fontSize: '12px', color: '#C9D1D9', bgcolor: '#161B22' }} />
              <Chip label={`Avg. Response: ${status.averageResponseTime}ms`} sx={{ fontSize: '12px', color: '#C9D1D9', bgcolor: '#161B22' }} />
              <Chip label={`Current Errors: ${status.currentErrors}`} sx={{ fontSize: '12px', color: '#C9D1D9', bgcolor: '#161B22' }} />
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: responseTimeTrend,
                  color: '#58A6FF',
                  curve: 'natural',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'point',
                  data: errorRateTrend.map((item) => item.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'responseTime' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#C9D1D9' }}
              />
              <ChartsYAxis
                axisId="responseTime"
                tickLabelStyle={{ fontSize: 10, fill: '#C9D1D9' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
